const results = $.steps.searchBusinesses.response.results || [];
const urls = results.map(r => r.url).filter(Boolean);
const unique = [...new Set(urls)].slice(0, 10);
const summaries = {};
results.forEach(r => { if (r.url) summaries[r.url] = { title: r.title || '', snippet: (r.text || '').slice(0, 300) }; });
return { urls: unique, summaries };

const iterations = $.steps.scrapeWebsites.response.iterations || [];
const urls = $.steps.extractUrls.output.urls;
const summaries = $.steps.extractUrls.output.summaries;
let sitesText = '';
iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const info = summaries[url] || {};
  const md = (iter.scrape && iter.scrape.response && iter.scrape.response.data) ? (iter.scrape.response.data.markdown || '') : '';
  sitesText += '--- SITE ' + (i+1) + ': ' + url + ' ---\n';
  sitesText += 'Title: ' + (info.title || 'N/A') + '\n';
  sitesText += 'Content:\n' + md.slice(0, 2000) + '\n\n';
});
return { sitesText, siteCount: urls.length };

let raw = $.steps.aiExtraction.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try {
  const leads = JSON.parse(raw);
  const rows = leads.map(l => [l.business_name || '', l.phone || '', l.email || '', l.address || '', l.website || '', l.category || '', l.description || '']);
  return { leads, rows };
} catch(e) {
  return { leads: [], rows: [], text: raw };
}
